select `ui`.`id` AS `id`,`ui`.`email` AS `email`,`ui`.`password` AS `password`,`ui`.`role_id` AS `role_id`,`ui`.`created_at` AS `joined_at`,`ui`.`profile_image` AS `profile_image`,coalesce(`sa`.`name`,`ad`.`name`,`em`.`name`,`dev`.`name`,concat(`v`.`first_name`,' ',`v`.`last_name`)) AS `name`,coalesce(`sa`.`employee_id`,`ad`.`employee_id`,`em`.`employee_id`,`dev`.`employee_id`,`v`.`vendor_id`) AS `employee_id`,`v`.`vendor_id` AS `vendor_id`,coalesce(`sa`.`status`,`ad`.`status`,`em`.`status`,`dev`.`status`,`v`.`status`) AS `status`,`em`.`department_id` AS `department_id`,coalesce(`sa`.`phone`,`v`.`phone`) AS `phone`,coalesce(`sa`.`company_name`,`v`.`company_name`) AS `company_name` from (((((`management_system`.`user_identities` `ui` left join `management_system`.`superadmins` `sa` on(`ui`.`id` = `sa`.`user_id`)) left join `management_system`.`admins` `ad` on(`ui`.`id` = `ad`.`user_id`)) left join `management_system`.`employees` `em` on(`ui`.`id` = `em`.`user_id`)) left join `management_system`.`developers` `dev` on(`ui`.`id` = `dev`.`user_id`)) left join `management_system`.`vendors` `v` on(`ui`.`id` = `v`.`user_id`))